examples.original_ir:
define i8 @test(i1 %c, ptr %p) {
entry:
  br i1 %c, label %if.then, label %if.end

if.then:
  br label %if.end

if.end:
  %phi = phi i32 [ undef, %entry ], [ 0, %if.then ]
  store i32 %phi, ptr %p
  %add = add i32 %phi, 64
  %trunc = trunc i32 %add to i8
  ret i8 %trunc
}

examples.optimized_ir:
define i8 @test(i1 %c, ptr %p) {
entry:
  br i1 %c, label %if.then, label %if.end

if.then:
  br label %if.end

if.end:
  %phi = phi i32 [ undef, %entry ], [ 0, %if.then ]
  store i32 %phi, ptr %p
  %add = add i32 %phi, 64
  %trunc = trunc nuw nsw i32 %add to i8
  ret i8 %trunc
}
